alu_combinatorial:
wire [32:0] aluMinus = {1'b1, ~aluIn1} + {1'b0, aluIn2} + 33'b1;

wire EQ  = (aluIn2 == aluIn1);
wire LT  = ($signed(aluIn2) < $signed(aluIn1));
wire LTU = (aluIn2 < aluIn1);

ram_idx_calc:
wire [IDXBITS-1:0] seed_idx    = 32'd[[[ core_memory_nonlinear_seed ]]] | 1'b1;

wire [IDXBITS-1:0] idx         = logical_idx * seed_idx;
wire [IDXBITS-1:0] load_idx    = logical_load_idx * seed_idx;

decrypt_instruction:
wire [31:0] key_input;
wire [31:0] instr_key;
wire [31:0] instr_dec;

assign key_input = 32'd[[[ core_crypt_seed ]]] + PC;
assign instr_key = (key_input * 32'd1732714) + 32'd1182730741;
assign instr_dec = mem_rdata ^ instr_key;

decrypt_ram:
// decrypt ram
    mem_rdata = ram[idx] ^ (
        ((32'd[[[ core_ram_seed ]]] + logical_idx) * 32'd1732714) + 32'd1182730741
    );

encrypt_ram:
// Encrypt ram
wire [31:0] mem_wdata_enc = mem_wdata ^ (
    ((32'd[[[ core_ram_seed ]]] + logical_idx) * 32'd1732714) + 32'd1182730741
);
